// Mezcla estado previo + patch -> registro final de columnas para conversation_state.
const p = $('Validar y Parsear').item.json;
const from = p.from || '';
let row = {};
try { row = $('Cargar Estado').item.json || {}; } catch (e) { row = {}; }
const hadRow = !!(row && row.celular);
const cur = $json || {};
const patch = cur.patch || {};
const nextPaso = patch.paso || cur.next_paso || row.paso || 'inicio';
function pick(k, dflt){ return (patch[k] !== undefined) ? patch[k] : ((row[k] !== undefined && row[k] !== null) ? row[k] : dflt); }
const rec = {
  celular: (from || '').replace(/^57/, ''),
  paso: nextPaso,
  distinct_id: pick('distinct_id', null),
  nombre: pick('nombre', null),
  correo: pick('correo', null),
  cedula: pick('cedula', null),
  ocupacion: pick('ocupacion', null),
  tags: pick('tags', null),
  participante_existe: pick('participante_existe', null),
  id_actividad_foto: pick('id_actividad_foto', null),
  datos: pick('datos', {}),
  intentos: pick('intentos', 0),
  last_activity_at: new Date().toISOString(),
  had_row: hadRow,
  wa_payload: cur.wa_payload
};
return [{ json: rec }];
